('86512fd3-c85c-45b1-ab54-4b275ec6686f', 'SUP-2025-000019', '5fc86254-ee42-4afb-b9da-c143d68c5995', 'Bianca Santos', 'ee54a8a5-47b1-4059-881a-381b9f5b82f1', 'Licitações', '2025-11-15T17:20:05.815Z', 'interno', 'software', NULL, 'Yuri, os contratos que estamos salvando estão sendo salvos com data errada, por exemplo Rinopolis, foi cadastrado com as datas de 22/09/2025 até 21/09/2026, no entanto depois de salvo e sistema deixou salvo como 21/09/2025 até 20/09/2026, preciso da data correta. Outra questão são os prazos de vencimentos, preciso que os avisos de vencimento sejam automaticos com 60 dias ou que possamos colocar manual entre entre 60 e 30 o aviso.', 'concluido', '{}', '{}', '2025-11-18T11:49:11.932Z', NULL, '2025-11-15T17:20:05.815Z', '2025-11-18T11:49:13.734Z', 'TI', '2025-11-18T11:49:10.354Z', NULL, 'pendente', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
